package com.chaobo.scm.supplier.application.contract;

import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.LocalDate;
@Service public class PriceAgreementQueryApplicationService {private final PriceAgreementReadModelPort read;public PriceAgreementQueryApplicationService(PriceAgreementReadModelPort read){this.read=read;}@Transactional(readOnly=true)public PageResult<PriceAgreementView> page(Long supplierId,Long scope,String skuCode,int pageNo,int pageSize){check(pageNo,pageSize);return read.page(scope==null?supplierId:scope,skuCode,pageNo,pageSize);}@Transactional(readOnly=true)public PriceAgreementView detail(long id,Long scope){var value=read.detail(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"价格协议不存在"));if(scope!=null&&scope!=value.supplierId())throw new BusinessException(ErrorCode.NOT_FOUND,"价格协议不存在");return value;}@Transactional(readOnly=true)public PriceAgreementView.Line validate(long supplierId,String skuCode,String currency,LocalDate date){return read.activeLine(supplierId,skuCode,currency,date==null?LocalDate.now():date).orElseThrow(()->new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"不存在有效价格协议或价格协议行"));}private static void check(int page,int size){if(page<1||size<1||size>100)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"分页参数不合法");}}
